// JavaScript code
const openButton = document.getElementById("open-button");
const dropdownMenu = document.getElementById("dropdown-menu");
const options = document.querySelectorAll("#dropdown-menu li");

openButton.addEventListener("click", () => {
  dropdownMenu.classList.toggle("hidden");
});

options.forEach(option => {
  option.addEventListener("click", () => {
    dropdownMenu.classList.add("hidden");
    openButton.textContent = option.textContent;
  });
});

// Add ARIA attributes for accessibility
openButton.setAttribute("aria-expanded", "false");
openButton.setAttribute("aria-controls", "dropdown-menu");
dropdownMenu.setAttribute("aria-label", "Dropdown menu");
options.forEach(option => {
  option.setAttribute("aria-label", "Dropdown option");
});
